const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const SRC = path.join(PROJECT, 'src');

const readFile = (rel) => {
  try { return fs.readFileSync(path.join(SRC, rel), 'utf8'); }
  catch { return '// FILE NOT FOUND'; }
};

// Read design brief from previous pipeline
let designBrief = '{}';
try {
  designBrief = fs.readFileSync(path.join(PROJECT, '.claude/design-brief.json'), 'utf8');
} catch (e) {
  designBrief = JSON.stringify({ error: 'design-brief.json not found — run ae-ui-research first' });
}

// Read current UI files for context
const files = {
  'index.css': readFile('index.css'),
  'App.tsx': readFile('App.tsx'),
  'button.tsx': readFile('components/ui/button.tsx'),
  'input.tsx': readFile('components/ui/input.tsx'),
  'select.tsx': readFile('components/ui/select.tsx'),
  'card.tsx': readFile('components/ui/card.tsx'),
  'tabs.tsx': readFile('components/ui/tabs.tsx'),
  'label.tsx': readFile('components/ui/label.tsx'),
  'badge.tsx': readFile('components/ui/badge.tsx'),
  'AntennaForm.tsx': readFile('components/AntennaForm/AntennaForm.tsx'),
  'FrequencyPresets.tsx': readFile('components/FrequencyPresets/FrequencyPresets.tsx'),
  'OptimizationPanel.tsx': readFile('components/OptimizationPanel/OptimizationPanel.tsx'),
  'SmithChart.tsx': readFile('components/SmithChart/SmithChart.tsx'),
  'RadiationPatternView.tsx': readFile('components/RadiationPatternView.tsx'),
  'AntennaViewport.tsx': readFile('viewport/AntennaViewport.tsx'),
};

return [{ json: { designBrief, files } }];

const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const CLAUDE_DIR = path.join(PROJECT, '.claude');

if (!fs.existsSync(CLAUDE_DIR)) fs.mkdirSync(CLAUDE_DIR, { recursive: true });

const output = $('Merge Spec').item.json.output || '';

// Parse and write ui-spec.json
let specJson = output;
try {
  specJson = specJson.replace(/^```json\n?/m, '').replace(/\n?```$/m, '').trim();
  const parsed = JSON.parse(specJson);
  specJson = JSON.stringify(parsed, null, 2);
} catch (e) {
  specJson = JSON.stringify({ raw_output: output, parse_error: e.message }, null, 2);
}

const specPath = path.join(CLAUDE_DIR, 'ui-spec.json');
fs.writeFileSync(specPath, specJson);

// Save all intermediate outputs
const allOutputs = {
  layout: $('Layout Architect').item.json.output || '',
  forms: $('Form UX Designer').item.json.output || '',
  charts: $('Chart/Viz Designer').item.json.output || '',
  viewport: $('3D Viewport Designer').item.json.output || '',
  tokens: $('Design Token Designer').item.json.output || '',
  merged: specJson,
};

const fullPath = path.join(CLAUDE_DIR, 'ui-design-spec-full.json');
fs.writeFileSync(fullPath, JSON.stringify(allOutputs, null, 2));

return [{ json: { status: 'OK', spec_path: specPath, full_path: fullPath, spec_preview: specJson.substring(0, 500) + '...' } }];
